1	import { Injectable } from '@angular/core';
2	import { DbService, Resident, AuditLog } from './db.service';
3	import { AuditAction, AuditService } from './audit.service';
4	import { AuthService } from './auth.service';
5	import { CryptoService } from './crypto.service';
6	import DOMPurify from 'dompurify';
7	
8	// =====================================================
9	// Public Types
10	// =====================================================
11	
12	export interface ResidentFilters {
13	  status?:     ('active' | 'inactive' | 'pending')[];
14	  buildingId?: number;
15	  search?:     string;
16	}
17	
18	export type CreateResidentData = Omit<
19	  Resident,
20	  'id' | 'encryptedId' | 'notes' | 'consentGiven' | 'consentTimestamp' | 'createdAt' | 'updatedAt'
21	>;
22	
23	export type UpdateResidentData = Partial<
24	  Omit<Resident, 'id' | 'encryptedId' | 'createdAt'>
25	>;
26	
27	// =====================================================
28	// ResidentService
29	// =====================================================
30	
31	@Injectable({ providedIn: 'root' })
32	export class ResidentService {
33	
34	  constructor(
35	    private db:          DbService,
36	    private audit:       AuditService,
37	    private authService: AuthService,
38	    private crypto:      CryptoService,
39	  ) {}
40	
41	  private requireRole(...allowedRoles: string[]): void {
42	    const current = this.authService.getCurrentRole();
43	    if (!current || !allowedRoles.includes(current)) {
44	      throw new Error(`Unauthorized: requires role ${allowedRoles.join(' or ')}`);
45	    }
46	  }
47	
48	  private requireSelfOrRole(resourceOwnerId: number, ...allowedRoles: string[]): void {
49	    const current = this.authService.getCurrentRole();
50	    const currentUserId = this.authService.getCurrentUserId();
51	    if (!current) throw new Error('Unauthorized: not authenticated');
52	    if (allowedRoles.includes(current)) return;
53	    if (current === 'resident' && currentUserId === resourceOwnerId) return;
54	    throw new Error('Unauthorized: insufficient permissions');
55	  }
56	
57	  // --------------------------------------------------
58	  // Session key (derived from user password on login)
59	  // --------------------------------------------------
60	
61	  private getSessionKey(): CryptoKey {
62	    const key = this.crypto.getSessionKey();
63	    if (!key) throw new Error('No active session key — please log in');
64	    return key;
65	  }
66	
67	  // --------------------------------------------------
68	  // getResidents — with optional filters
69	  // --------------------------------------------------
70	
71	  async getResidents(filters?: ResidentFilters): Promise<Resident[]> {
72	    this.requireRole('admin', 'compliance');
73	    let residents = await this.db.residents.toArray();
74	
75	    if (!filters) return residents;
76	
77	    // Status filter
78	    if (filters.status && filters.status.length > 0) {
79	      residents = residents.filter(r => filters.status!.includes(r.status));
80	    }
81	
82	    // Full-text search (name / email)
83	    if (filters.search?.trim()) {
84	      const q = filters.search.toLowerCase().trim();
85	      residents = residents.filter(r =>
86	        r.firstName.toLowerCase().includes(q) ||
87	        r.lastName.toLowerCase().includes(q)  ||
88	        r.email.toLowerCase().includes(q),
89	      );
90	    }
91	
92	    // Building filter — join through occupancy → room → unit → building
93	    if (filters.buildingId !== undefined) {
94	      const units   = await this.db.units.where('buildingId').equals(filters.buildingId).toArray();
95	      const unitIds = units.map(u => u.id!);
96	      const rooms   = await this.db.rooms.filter(r => unitIds.includes(r.unitId)).toArray();
97	      const roomIds = new Set(rooms.map(r => r.id!));
98	      const occs    = await this.db.occupancies
99	        .filter(o => o.status === 'active' && roomIds.has(o.roomId))
100	        .toArray();
101	      const inBuilding = new Set(occs.map(o => o.residentId));
102	      residents = residents.filter(r => inBuilding.has(r.id!));
103	    }
104	
105	    return residents;
106	  }
107	
108	  // --------------------------------------------------
109	  // getResident
110	  // --------------------------------------------------
111	
112	  async getResident(id: number, callerRole?: string): Promise<Resident | undefined> {
113	    this.requireSelfOrRole(id, 'admin', 'compliance');
114	    const role = callerRole ?? this.authService.getCurrentRole() ?? undefined;
115	    const resident = await this.db.residents.get(id);
116	    if (resident) await this.decryptConfidentialNotes(resident, role);
117	    return resident;
118	  }
119	
120	  private async decryptConfidentialNotes(resident: Resident, callerRole?: string): Promise<void> {
121	    const canRead = callerRole === 'admin' || callerRole === 'compliance';
122	    const key = this.crypto.getSessionKey();
123	    for (const note of resident.notes) {
124	      if (note.confidential && note.encryptedText && canRead && key) {
125	        try {
126	          const dotIdx = note.encryptedText.indexOf('.');
127	          if (dotIdx > 0) {
128	            note.text = await this.crypto.decryptRaw(
129	              note.encryptedText.slice(0, dotIdx),
130	              note.encryptedText.slice(dotIdx + 1),
131	              key,
132	            );
133	          }
134	        } catch {
135	          // Decryption failed — keep redacted placeholder
136	        }
137	      }
138	    }
139	  }
140	
141	  // --------------------------------------------------
142	  // createResident — encrypts identifier, writes audit
143	  // --------------------------------------------------
144	
145	  async createResident(
146	    data:      CreateResidentData,
147	    actorId:   number,
148	    actorRole: string,
149	  ): Promise<Resident> {
150	    this.requireRole('admin');
151	    const now = new Date();
152	
153	    // Generate a unique opaque identifier then encrypt with AES-GCM
154	    const rawId = `res-${Date.now()}-${Math.random().toString(36).slice(2, 9)}`;
155	    const key   = this.getSessionKey();
156	    const { ciphertext, iv } = await this.crypto.encryptRaw(rawId, key);
157	    const encryptedId = `${ciphertext}.${iv}`;
158	
159	    const id = await this.db.residents.add({
160	      firstName:    DOMPurify.sanitize(data.firstName.trim()),
161	      lastName:     DOMPurify.sanitize(data.lastName.trim()),
162	      email:        DOMPurify.sanitize(data.email.trim().toLowerCase()),
163	      phone:        DOMPurify.sanitize((data.phone ?? '').trim()),
164	      dateOfBirth:  data.dateOfBirth,
165	      status:       data.status,
166	      encryptedId,
167	      notes:        [],
168	      consentGiven: false,
169	      createdAt:    now,
170	      updatedAt:    now,
171	    });
172	
173	    const resident = await this.db.residents.get(id);
174	    // Never log the encrypted ID in audit snapshots
175	    this.audit.log(
176	      AuditAction.RESIDENT_CREATED,
177	      actorId, actorRole,
178	      'resident', id,
179	      undefined,
180	      { ...resident, encryptedId: '[ENCRYPTED]' },
181	    );
182	
183	    return resident!;
184	  }
185	
186	  // --------------------------------------------------
187	  // updateResident — snapshots before/after, warns on
188	  // inactive status when active occupancy exists
189	  // --------------------------------------------------
190	
191	  async updateResident(
192	    id:        number,
193	    data:      UpdateResidentData,
194	    actorId:   number,
195	    actorRole: string,
196	  ): Promise<{ resident: Resident; warnings: string[] }> {
197	    this.requireRole('admin', 'resident', 'compliance');
198	    const before = await this.db.residents.get(id);
199	    if (!before) throw new Error('RESIDENT_NOT_FOUND');
200	
201	    const warnings: string[] = [];
202	
203	    // Warn: marking inactive while still assigned to a room
204	    if (data.status === 'inactive' && before.status !== 'inactive') {
205	      const activeOcc = await this.db.occupancies
206	        .filter(o => o.residentId === id && o.status === 'active')
207	        .first();
208	      if (activeOcc) {
209	        const room = await this.db.rooms.get(activeOcc.roomId);
210	        warnings.push(
211	          `Resident has an active room assignment (Room ${room?.roomNumber ?? activeOcc.roomId}). ` +
212	          `Consider moving them out before deactivating.`,
213	        );
214	      }
215	    }
216	
217	    // Sanitize mutable text fields
218	    const sanitized: UpdateResidentData = { ...data };
219	    if (data.firstName) sanitized.firstName = DOMPurify.sanitize(data.firstName.trim());
220	    if (data.lastName)  sanitized.lastName  = DOMPurify.sanitize(data.lastName.trim());
221	    if (data.email)     sanitized.email     = DOMPurify.sanitize(data.email.trim().toLowerCase());
222	    if (data.phone)     sanitized.phone     = DOMPurify.sanitize((data.phone ?? '').trim());
223	
224	    // Encrypt confidential notes at rest
225	    if (sanitized.notes) {
226	      const key = this.crypto.getSessionKey();
227	      for (const note of sanitized.notes) {
228	        if (note.confidential && note.text && note.text !== '[CONFIDENTIAL]') {
229	          if (key) {
230	            const { ciphertext, iv } = await this.crypto.encryptRaw(note.text, key);
231	            note.encryptedText = `${ciphertext}.${iv}`;
232	            note.text = '[CONFIDENTIAL]';
233	          }
234	        }
235	      }
236	    }
237	
238	    await this.db.residents.update(id, { ...sanitized, updatedAt: new Date() });
239	    const after = await this.db.residents.get(id);
240	
241	    this.audit.log(
242	      AuditAction.RESIDENT_UPDATED,
243	      actorId, actorRole,
244	      'resident', id,
245	      { ...before, encryptedId: '[ENCRYPTED]' },
246	      { ...after,  encryptedId: '[ENCRYPTED]' },
247	    );
248	
249	    return { resident: after!, warnings };
250	  }
251	
252	  // --------------------------------------------------
253	  // getChangeLog — audit entries for a specific resident
254	  // --------------------------------------------------
255	
256	  async getChangeLog(residentId: number): Promise<AuditLog[]> {
257	    this.requireRole('admin', 'compliance');
258	    const logs = await this.db.auditLogs
259	      .filter(l => l.targetType === 'resident' && Number(l.targetId) === residentId)
260	      .toArray();
261	    return logs.sort(
262	      (a, b) => new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime(),
263	    );
264	  }
265	
266	  // --------------------------------------------------
267	  // searchResidents — simple in-memory text search
268	  // (Phase 7 will wire this into the full search index)
269	  // --------------------------------------------------
270	
271	  async searchResidents(query: string): Promise<Resident[]> {
272	    this.requireRole('admin', 'compliance');
273	    if (!query.trim()) return [];
274	    const q = query.toLowerCase().trim();
275	    const all = await this.db.residents.toArray();
276	    return all.filter(r =>
277	      r.firstName.toLowerCase().includes(q) ||
278	      r.lastName.toLowerCase().includes(q)  ||
279	      r.email.toLowerCase().includes(q)     ||
280	      r.phone.includes(q),
281	    );
282	  }
283	}
