30	// =====================================================
31	// SearchService — Lunr.js full-text + facets + synonyms
32	// =====================================================
33	
34	@Injectable({ providedIn: 'root' })
35	export class SearchService {
36	
37	  private _lunrIndex: import('lunr').Index | null = null;
38	  private _indexedEntries: SearchIndexEntry[] = [];
39	
40	  constructor(
41	    private db:      DbService,
42	    private anomaly: AnomalyService,
43	  ) {}
44	
45	  // --------------------------------------------------
46	  // Index Management
47	  // --------------------------------------------------
48	
49	  /**
50	   * Build an in-memory Lunr index from the searchIndex store.
51	   * Call this once after DB is populated, and whenever entries change.
52	   */
53	  async buildIndex(): Promise<void> {
54	    // Exclude internal _trending entries from the search index
55	    this._indexedEntries = await this.db.searchIndex
56	      .filter(e => e.entityType !== '_trending')
57	      .toArray();
58	
59	    const entries = this._indexedEntries;
60	
61	    this._lunrIndex = lunr(function () {
62	      this.field('title',    { boost: 10 });
63	      this.field('body',     { boost:  5 });
64	      this.field('tags',     { boost:  3 });
65	      this.field('category', { boost:  2 });
66	      this.field('building');
67	      this.ref('id');
68	
69	      for (const entry of entries) {
70	        this.add({
71	          id:       String(entry.id ?? entry.entityId),
72	          title:    entry.title ?? '',
73	          body:     entry.body  ?? '',
74	          tags:     (entry.tags ?? []).join(' '),
75	          category: entry.category ?? '',
76	          building: entry.building ?? '',
77	        });
78	      }
79	    });
80	  }
81	
82	  // --------------------------------------------------
83	  // Search
84	  // --------------------------------------------------
85	
86	  /**
87	   * Full search pipeline:
88	   *   1. recordSearch (anomaly detection)
89	   *   2. Synonym expand query
90	   *   3. Lunr full-text search
91	   *   4. Spell-correction fallback (if 0 results)
92	   *   5. Zero-results log
93	   *   6. Facet filter
94	   *   7. Trend tracking
95	   */
96	  async search(
97	    query:   string,
98	    userId?: number,
99	    filters?: SearchFilters,
100	  ): Promise<SearchResult[]> {
101	    this.anomaly.recordSearch();
102	
103	    const trimmed = query.trim();
104	    if (!trimmed) return [];
105	
106	    // Rebuild index if stale
107	    if (!this._lunrIndex) await this.buildIndex();
108	
109	    // Synonym expansion
110	    const { expandedTerms, spellSuggestion } = await this.expandQuery(trimmed);
111	
112	    // Lunr search — try expanded query first
113	    let lunrQuery = expandedTerms.join(' ');
114	    let lunrResults = this._safeSearch(lunrQuery);
115	
116	    // Spell-correction fallback
117	    if (lunrResults.length === 0 && spellSuggestion) {
118	      lunrResults = this._safeSearch(spellSuggestion);
119	    }
120	
121	    // Map lunr results to SearchResult objects
122	    const scoreMap = new Map<string, number>();
123	    for (const r of lunrResults) scoreMap.set(r.ref, r.score);
124	
125	    let results: SearchResult[] = [];
126	
127	    for (const entry of this._indexedEntries) {
128	      const ref = String(entry.id ?? entry.entityId);
129	      if (!scoreMap.has(ref)) continue;
130	
131	      results.push({
132	        entry,
133	        score:      scoreMap.get(ref)!,
134	        highlights: expandedTerms,
135	      });
136	    }
137	
138	    results.sort((a, b) => b.score - a.score);
139	
140	    // Apply facet filters
141	    if (filters) results = this._applyFilters(results, filters);
142	
143	    // Zero-results log
144	    if (results.length === 0) {
145	      await this.db.zeroResultsLog.add({
146	        query:     trimmed,
147	        timestamp: new Date(),
148	        userId,
149	      });
150	    }
151	
152	    // Trend tracking
153	    await this._trackTrending(trimmed);
154	
155	    return results;
156	  }
