170	  // --------------------------------------------------
171	  // Facets
172	  // --------------------------------------------------
173	
174	  async getFacets(): Promise<SearchFacets> {
175	    const entries = await this.db.searchIndex
176	      .filter(e => e.entityType !== '_trending')
177	      .toArray();
178	
179	    const catCounts   = new Map<string, number>();
180	    const bldgCounts  = new Map<string, number>();
181	    const mediaCounts = new Map<string, number>();
182	
183	    for (const e of entries) {
184	      if (e.category) catCounts.set(e.category, (catCounts.get(e.category) ?? 0) + 1);
185	      if (e.building) bldgCounts.set(e.building, (bldgCounts.get(e.building) ?? 0) + 1);
186	      const mt = e.metadata?.['mimeType'] as string | undefined;
187	      if (mt) mediaCounts.set(mt, (mediaCounts.get(mt) ?? 0) + 1);
188	    }
