312	        const corrEntry = await this.db.searchDictionary
313	          .filter(d => d.corrections.some(c => c.toLowerCase() === lower))
314	          .first();
315	        if (corrEntry) {
316	          spellSuggestion = corrEntry.term;
317	          terms.push(corrEntry.term);
318	          terms.push(...corrEntry.synonyms);
319	        }
320	      }
321	    }
322	
323	    return { expandedTerms: [...new Set(terms)], spellSuggestion };
324	  }
325	
326	  private _applyFilters(results: SearchResult[], filters: SearchFilters): SearchResult[] {
327	    return results.filter(({ entry }) => {
328	      if (filters.category  && entry.category !== filters.category)   return false;
329	      if (filters.building  && entry.building !== filters.building)   return false;
330	      if (filters.from      && entry.createdAt < filters.from)        return false;
331	      if (filters.to        && entry.createdAt > filters.to)          return false;
332	      if (filters.mediaType) {
333	        const mt = entry.metadata?.['mimeType'] as string | undefined;
334	        if (mt !== filters.mediaType) return false;
335	      }
336	      return true;
337	    });
338	  }
339	
340	  private async _trackTrending(query: string): Promise<void> {
341	    const today = new Date();
342	    today.setHours(0, 0, 0, 0);
343	
344	    const existing = await this.db.searchIndex
345	      .filter(e => e.entityType === '_trending' && e.title === query)
346	      .first();
347	
348	    if (existing?.id) {
349	      const count = ((existing.metadata?.['count'] as number) ?? 0) + 1;
350	      await this.db.searchIndex.update(existing.id, {
351	        metadata: { ...existing.metadata, count },
352	      });
353	    } else {
354	      await this.db.searchIndex.add({
355	        entityType: '_trending',
356	        entityId:   query,
357	        title:      query,
358	        body:       '',
359	        tags:       [],
360	        metadata:   { count: 1, date: today.toISOString() },
361	        createdAt:  new Date(),
362	      });
363	    }
364	  }
