363	export class AppComponent implements OnInit, OnDestroy {
364	
365	  showSidebar = false;
366	  sidebarCollapsed = false;
367	  currentRole: UserRole | null = null;
368	  unreadCount = 0;
369	  pageTitle = 'HarborPoint';
370	
371	  // Re-auth modal state
372	  reAuthOpen         = false;
373	  reAuthLoading      = false;
374	  reAuthPassword     = '';
375	  reAuthError        = '';
376	  reAuthAttemptsLeft = 3;
377	  private _pendingAnomaly: AnomalyEvent | null = null;
378	
379	  private subs: Subscription[] = [];
380	
381	  get visibleNavItems(): NavItem[] {
382	    if (!this.currentRole) return [];
383	    return NAV_ITEMS.filter(item => item.roles.includes(this.currentRole!));
384	  }
385	
386	  get roleLabel(): string {
387	    return this.currentRole ? ROLE_LABELS[this.currentRole] : '';
388	  }
389	
390	  constructor(
391	    private auth:      AuthService,
392	    private router:    Router,
393	    private messaging: MessagingService,
394	    private anomaly:   AnomalyService,
395	    private themeService: ThemeService,
396	  ) {}
397	
398	  ngOnInit(): void {
399	    // Load theme before first render
400	    this.themeService.init();
401	
402	    // Track auth state — redirect to /login on lock
403	    this.subs.push(
404	      this.auth.state$.subscribe(state => {
405	        const wasLoggedIn = this.currentRole !== null;
406	        this.currentRole = state.role;
407	        this.loadUnreadCount();
408	
409	        if (wasLoggedIn && (state.isLocked || !state.isLoggedIn)) {
410	          this.router.navigate(['/login']);
411	        }
412	      }),
413	    );
414	
415	    // Track route changes to control sidebar visibility and page title
416	    this.subs.push(
417	      this.router.events.pipe(
418	        filter(event => event instanceof NavigationEnd),
419	      ).subscribe((event) => {
420	        const url = (event as NavigationEnd).urlAfterRedirects;
421	        this.showSidebar = !HIDDEN_SIDEBAR_ROUTES.some(r => url.startsWith(r));
422	        this.pageTitle = this.getTitleForRoute(url);
423	      }),
424	    );
425	
426	    // Restore sidebar state from localStorage
427	    const collapsed = localStorage.getItem('hp_sidebar');
428	    if (collapsed) this.sidebarCollapsed = collapsed === 'true';
429	
430	    // Subscribe to anomaly events → show re-auth modal
431	    this.subs.push(
432	      this.anomaly.anomalyDetected$.subscribe(event => {
433	        this._pendingAnomaly    = event;
434	        this.reAuthPassword     = '';
435	        this.reAuthError        = '';
436	        this.reAuthAttemptsLeft = 3;
437	        this.reAuthOpen         = true;
438	      }),
439	    );
440	  }
441	
442	  private async loadUnreadCount(): Promise<void> {
443	    if (!this.currentRole) { this.unreadCount = 0; return; }
444	    try {
445	      this.unreadCount = await this.messaging.getUnreadCount();
446	    } catch {
447	      this.unreadCount = 0;
448	    }
449	  }
450	
451	  toggleSidebar(): void {
452	    this.sidebarCollapsed = !this.sidebarCollapsed;
453	    localStorage.setItem('hp_sidebar', String(this.sidebarCollapsed));
454	  }
455	
456	  lockSession(): void {
457	    this.anomaly.reset();
458	    this.auth.lockSession();
459	  }
460	
461	  // --------------------------------------------------
462	  // Re-auth modal handlers
463	  // --------------------------------------------------
464	
465	  async onReAuthConfirm(): Promise<void> {
466	    if (this.reAuthLoading || !this.reAuthPassword) return;
467	    this.reAuthLoading = true;
468	    this.reAuthError   = '';
469	
470	    try {
471	      const ok = await this.auth.reAuthenticate(this.reAuthPassword);
472	      if (ok) {
473	        this.reAuthOpen    = false;
474	        this.reAuthPassword = '';
475	        this._pendingAnomaly = null;
476	      } else {
