835	    const name = `${first ?? ''}${last ?? ''}`;
836	    if (!name.trim()) return '#1e3a5f';
837	    let hash = 0;
838	    for (let i = 0; i < name.length; i++) {
839	      hash = (hash * 31 + name.charCodeAt(i)) & 0xffffffff;
840	    }
841	    return this.AVATAR_COLORS[Math.abs(hash) % this.AVATAR_COLORS.length];
