94	  // uploadDocument
95	  // Validates type / size / per-resident count, then
96	  // SHA-256 hashes the file (encrypted at rest),
97	  // encrypts file data, stores with pending_review.
98	  // --------------------------------------------------
99	
100	  async uploadDocument(
101	    residentId:      number,
102	    file:            File,
103	    consentRecordId: number,
104	    actorId:         number,
105	    actorRole:       string,
106	  ): Promise<HpDocument> {
107	
108	    this.requireRole('resident', 'admin');
109	
110	    // ── Consent validation ─────────────────────────
111	    const consentStatus = await this.getConsentStatus(residentId);
112	    if (!consentStatus.granted) {
113	      throw new Error('Upload rejected: resident has not granted document consent');
114	    }
115	    const consentRecord = await this.db.consentRecords.get(consentRecordId);
116	    if (!consentRecord || consentRecord.residentId !== residentId || consentRecord.action !== 'granted') {
117	      throw new Error('Upload rejected: invalid or mismatched consent record');
118	    }
119	
120	    // ── Content policy check on file name ────────────
121	    const policyResult = await this.contentPolicy.evaluate(file.name);
122	    if (policyResult.action === 'block') {
123	      throw new Error('Document upload blocked by content safety policy');
124	    }
125	
126	    // ── Validation ──────────────────────────────────
127	    if (!this.ALLOWED_MIME_TYPES.includes(file.type as never)) {
128	      throw new Error('INVALID_FILE_TYPE');
129	    }
130	    if (file.size > this.MAX_FILE_SIZE_BYTES) {
131	      throw new Error('FILE_TOO_LARGE');
132	    }
133	    const existingCount = await this.db.documents
134	      .where('residentId').equals(residentId)
135	      .count();
136	    if (existingCount >= this.MAX_FILES_PER_RESIDENT) {
137	      throw new Error('MAX_FILES_REACHED');
138	    }
139	
140	    const buffer = await file.arrayBuffer();
141	    const key    = this.getKey();
142	
143	    // ── SHA-256 hash — encrypted at rest ────────────
144	    const rawHash = await this.crypto.hashFile(buffer);
145	    const { ciphertext: hc, iv: hiv } = await this.crypto.encryptRaw(rawHash, key);
146	    const fileHash = `${hc}.${hiv}`;
147	
