136	  async sendMessage(params: {
137	    threadId:    number;
138	    recipientId?: number;
139	    rawBody:     string;
140	    type:        'announcement' | 'direct';
141	    templateId?: number;
142	  }): Promise<Message> {
143	    const senderId = this.auth.getCurrentUserId();
144	    const senderRole = this.auth.getCurrentRole();
145	    if (senderId == null || !senderRole) throw new Error('Unauthorized: no active session');
146	
147	    // Verify sender is participant (non-admin, non-announcement)
148	    if (senderRole !== 'admin' && params.type !== 'announcement') {
149	      const thread = await this.db.threads.get(params.threadId);
150	      if (!thread) throw new Error('Thread not found');
151	      if (!thread.participantIds.includes(senderId)) {
152	        throw new Error('Unauthorized: sender is not a participant in this thread');
153	      }
154	    }
155	
156	    const sanitized = DOMPurify.sanitize(params.rawBody);
157	    const masked    = maskSensitiveContent(sanitized);
158	
159	    // Content policy enforcement
160	    const policyResult = await this.contentPolicy.evaluate(masked);
161	    if (policyResult.action === 'block') {
162	      throw new Error('Message blocked by content safety policy');
163	    }
164	
165	    // Encrypt original (pre-mask) body for audit trail
166	    let encryptedOriginal: string | undefined;
167	    try {
168	      const sessionKey = this.crypto.getSessionKey();
169	      if (!sessionKey) throw new Error('No session key');
170	      const { ciphertext, iv } = await this.crypto.encryptRaw(sanitized, sessionKey);
171	      const payload = { ciphertext, iv };
172	      encryptedOriginal = JSON.stringify(payload);
173	    } catch {
174	      encryptedOriginal = undefined;
175	    }
176	
177	    const id = await this.db.messages.add({
178	      threadId:     params.threadId,
179	      senderId,
180	      senderRole,
181	      recipientId:  params.recipientId,
182	      body:         masked,
183	      originalBody: encryptedOriginal,
184	      type:         params.type,
185	      readBy:       [],
186	      deleted:      false,
187	      templateId:   params.templateId,
188	      createdAt:    new Date(),
189	    });
190	
191	    await this.db.threads.update(params.threadId, { lastMessageAt: new Date() });
192	
193	    this.audit.log(AuditAction.MESSAGE_SENT, senderId, senderRole, 'message', id);
194	
195	    const msg = await this.db.messages.get(id);
196	    return msg!;
197	  }
198	
199	  async deleteMessage(messageId: number): Promise<void> {
200	    this.requireRole('admin');
201	    const actorId = this.auth.getCurrentUserId()!;
202	    const actorRole = this.auth.getCurrentRole()!;
203	    const msg = await this.db.messages.get(messageId);
204	    if (!msg) throw new Error('Message not found');
205	
206	    await this.db.messages.update(messageId, {
207	      deleted:   true,
208	      deletedAt: new Date(),
209	      deletedBy: actorId,
210	    });
211	
212	    this.audit.log(AuditAction.MESSAGE_DELETED, actorId, actorRole, 'message', messageId, msg);
213	  }
