216	export class MoveInModalComponent implements OnChanges {
217	
218	  @Input() open = false;
219	  @Input() room: Room | null = null;
220	  @Input() availableResidents: Resident[] = [];
221	  @Input() saving = false;
222	
223	  @Output() confirmed = new EventEmitter<MoveInPayload>();
224	  @Output() cancelled = new EventEmitter<void>();
225	
226	  form: FormGroup;
227	
228	  readonly reasonCodeOptions: SelectOption[] = [
229	    { value: ReasonCode.MOVE_IN_NEW,     label: 'New Resident' },
230	    { value: ReasonCode.TRANSFER,        label: 'Transfer' },
231	    { value: ReasonCode.LEASE_START,     label: 'Lease Start' },
232	    { value: ReasonCode.ADMINISTRATIVE,  label: 'Administrative' },
233	  ];
234	
235	  constructor(private fb: FormBuilder) {
236	    this.form = this.fb.group({
237	      residentId:   [null,                    Validators.required],
238	      reasonCode:   [ReasonCode.MOVE_IN_NEW,  Validators.required],
239	      effectiveFrom: [this.todayStr(),         Validators.required],
240	    });
241	  }
242	
243	  ngOnChanges(changes: SimpleChanges): void {
244	    if (changes['open'] && this.open) {
245	      this.form.reset({
246	        residentId:    null,
247	        reasonCode:    ReasonCode.MOVE_IN_NEW,
248	        effectiveFrom: this.todayStr(),
249	      });
250	    }
251	  }
252	
253	  get residentOptions(): SelectOption[] {
254	    return this.availableResidents.map(r => ({
255	      value: r.id!,
256	      label: `${r.firstName} ${r.lastName}`,
257	    }));
258	  }
259	
260	  get selectedResident(): Resident | null {
261	    const id = this.form.get('residentId')?.value;
262	    return id != null ? (this.availableResidents.find(r => r.id === Number(id)) ?? null) : null;
263	  }
264	
265	  onConfirm(): void {
266	    if (this.form.invalid) return;
267	    const { residentId, reasonCode, effectiveFrom } = this.form.value;
268	    this.confirmed.emit({
269	      residentId:    Number(residentId),
270	      reasonCode:    reasonCode as string,
271	      effectiveFrom: new Date(effectiveFrom as string),
272	    });
273	  }
274	
275	  private todayStr(): string {
276	    return new Date().toISOString().split('T')[0];
277	  }
278	}
