1	/**
2	 * Resident Integration Tests
3	 *
4	 * Tests: full CRUD lifecycle, encryption, audit trail,
5	 * filter-by-building join, inactive-occupancy warning,
6	 * change log ordering, search.
7	 */
8	
9	import 'fake-indexeddb/auto';
10	import { TestBed } from '@angular/core/testing';
11	
12	import { ResidentService } from '../src/app/core/services/resident.service';
13	import { PropertyService, ReasonCode } from '../src/app/core/services/property.service';
14	import { DbService } from '../src/app/core/services/db.service';
15	import { AuditService } from '../src/app/core/services/audit.service';
16	import { CryptoService } from '../src/app/core/services/crypto.service';
17	import { AuthService } from '../src/app/core/services/auth.service';
18	import { LoggerService } from '../src/app/core/services/logger.service';
19	
20	// ──────────────────────────────────────────────────────────────────────────────
21	// Helpers
22	// ──────────────────────────────────────────────────────────────────────────────
23	
24	async function setup() {
25	  TestBed.configureTestingModule({
26	    providers: [ResidentService, PropertyService, DbService, AuditService, CryptoService, AuthService, LoggerService],
27	  });
28	  const db = TestBed.inject(DbService);
29	  await db.open();
30	  await new Promise(r => setTimeout(r, 200));
31	  await TestBed.inject(AuthService).selectRole('admin', 'harborpoint2024');
32	  return {
33	    service:  TestBed.inject(ResidentService),
34	    property: TestBed.inject(PropertyService),
35	    db,
36	  };
37	}
38	
39	async function teardown(db: DbService) {
40	  await db.close();
41	  TestBed.resetTestingModule();
42	}
43	
44	const BASE = {
45	  firstName:   'Test',
46	  lastName:    'Resident',
47	  email:       'test@hp.local',
48	  phone:       '555-0000',
49	  dateOfBirth: new Date('1990-01-01'),
50	  status:      'active' as const,
51	};
52	
53	// ──────────────────────────────────────────────────────────────────────────────
54	// Create + Read
55	// ──────────────────────────────────────────────────────────────────────────────
56	
57	describe('Resident Integration — CRUD', () => {
58	  let service: ResidentService;
59	  let db: DbService;
60	
61	  beforeEach(async () => {
62	    ({ service, db } = await setup());
63	  });
64	  afterEach(async () => { await teardown(db); });
65	
66	  it('creates a resident and retrieves it by id', async () => {
67	    const created = await service.createResident(BASE, 1, 'admin');
68	    expect(created.id).toBeDefined();
69	
70	    const fetched = await service.getResident(created.id!);
71	    expect(fetched).toBeDefined();
72	    expect(fetched!.firstName).toBe('Test');
73	    expect(fetched!.email).toBe('test@hp.local');
74	  });
75	
76	  it('encryptedId is stored in ciphertext.iv format', async () => {
77	    const r = await service.createResident(BASE, 1, 'admin');
78	    const parts = r.encryptedId.split('.');
79	    expect(parts.length).toBe(2);
80	    expect(parts[0].length).toBeGreaterThan(0);
81	    expect(parts[1].length).toBeGreaterThan(0);
82	  });
83	
84	  it('getResidents returns the created resident', async () => {
85	    const created = await service.createResident(
86	      { ...BASE, email: 'unique-create@hp.local' }, 1, 'admin',
87	    );
88	    const all = await service.getResidents();
89	    expect(all.some(r => r.id === created.id)).toBe(true);
90	  });
91	
92	  it('updates a resident and persists changes', async () => {
93	    const r = await service.createResident(BASE, 1, 'admin');
94	    const { resident: updated } = await service.updateResident(
95	      r.id!, { firstName: 'Updated', status: 'pending' }, 1, 'admin',
96	    );
97	    expect(updated.firstName).toBe('Updated');
98	    expect(updated.status).toBe('pending');
99	
100	    const fetched = await service.getResident(r.id!);
101	    expect(fetched!.firstName).toBe('Updated');
102	  });
103	});
104	
105	// ──────────────────────────────────────────────────────────────────────────────
106	// Audit trail
107	// ──────────────────────────────────────────────────────────────────────────────
108	
109	describe('Resident Integration — Audit trail', () => {
110	  let service: ResidentService;
111	  let db: DbService;
112	
113	  beforeEach(async () => {
114	    ({ service, db } = await setup());
115	  });
116	  afterEach(async () => { await teardown(db); });
117	
118	  it('audit log contains RESIDENT_CREATED entry after create', async () => {
119	    const r = await service.createResident(BASE, 1, 'admin');
120	    const logs = await db.auditLogs
121	      .filter(l => l.action === 'RESIDENT_CREATED' && Number(l.targetId) === r.id)
122	      .toArray();
123	    expect(logs.length).toBeGreaterThanOrEqual(1);
124	  });
125	
126	  it('audit log after create does not expose raw encryptedId', async () => {
127	    const r = await service.createResident(BASE, 1, 'admin');
128	    const logs = await db.auditLogs
129	      .filter(l => Number(l.targetId) === r.id)
130	      .toArray();
131	    for (const log of logs) {
132	      expect(JSON.stringify(log.after ?? {})).not.toContain(r.encryptedId);
133	    }
134	  });
135	
136	  it('audit log contains RESIDENT_UPDATED with before/after snapshots', async () => {
137	    const r = await service.createResident(BASE, 1, 'admin');
138	    await service.updateResident(r.id!, { phone: '555-9876' }, 1, 'admin');
139	
140	    const logs = await db.auditLogs
141	      .filter(l => l.action === 'RESIDENT_UPDATED' && Number(l.targetId) === r.id)
142	      .toArray();
143	    expect(logs.length).toBeGreaterThanOrEqual(1);
144	    const update = logs[0];
145	    expect((update.before as Record<string, unknown>)?.['phone']).toBe('555-0000');
146	    expect((update.after  as Record<string, unknown>)?.['phone']).toBe('555-9876');
147	  });
148	});
149	
150	// ──────────────────────────────────────────────────────────────────────────────
151	// Filters
152	// ──────────────────────────────────────────────────────────────────────────────
153	
154	describe('Resident Integration — Filters', () => {
155	  let service: ResidentService;
156	  let property: PropertyService;
157	  let db: DbService;
158	
159	  beforeEach(async () => {
160	    ({ service, property, db } = await setup());
161	  });
162	  afterEach(async () => { await teardown(db); });
163	
164	  it('status filter returns only matching residents', async () => {
165	    await service.createResident({ ...BASE, email: 'a@hp.local', status: 'active' }, 1, 'admin');
166	    await service.createResident({ ...BASE, email: 'b@hp.local', status: 'inactive' }, 1, 'admin');
167	
168	    const active = await service.getResidents({ status: ['active'] });
169	    for (const r of active) {
170	      expect(r.status).toBe('active');
171	    }
172	
173	    const inactive = await service.getResidents({ status: ['inactive'] });
174	    for (const r of inactive) {
175	      expect(r.status).toBe('inactive');
176	    }
177	  });
178	
179	  it('search filter matches partial first name', async () => {
180	    await service.createResident({ ...BASE, firstName: 'Zelda', email: 'zelda@hp.local' }, 1, 'admin');
181	    await service.createResident({ ...BASE, firstName: 'Arthur', email: 'arthur@hp.local' }, 1, 'admin');
182	
183	    const results = await service.getResidents({ search: 'zelda' });
184	    expect(results.some(r => r.firstName === 'Zelda')).toBe(true);
185	    expect(results.every(r => r.firstName === 'Zelda' || r.lastName.toLowerCase().includes('zelda') || r.email.includes('zelda'))).toBe(true);
186	  });
187	
188	  it('buildingId filter returns only residents in that building', async () => {
189	    const buildings = await property.getBuildings();
190	    const building  = buildings[0];
191	
192	    // Create a room in the first building's unit
193	    const units = await property.getUnits(building.id!);
194	    if (units.length === 0) return; // seed data may not have units
195	
196	    const rooms = await property.getRooms(units[0].id!);
197	    if (rooms.length === 0) return;
198	
199	    const r = await service.createResident(
200	      { ...BASE, email: 'bldfilter@hp.local' }, 1, 'admin',
201	    );
202	
203	    await property.moveIn({
204	      residentId:    r.id!,
205	      roomId:        rooms[0].id!,
206	      effectiveFrom: new Date(),
207	      reasonCode:    ReasonCode.MOVE_IN_NEW,
208	      actorId:       1,
209	      actorRole:     'admin',
210	    });
211	
212	    const inBuilding = await service.getResidents({ buildingId: building.id! });
213	    expect(inBuilding.some(res => res.id === r.id)).toBe(true);
214	  });
215	});
216	
217	// ──────────────────────────────────────────────────────────────────────────────
218	// Inactive + occupancy warning
219	// ──────────────────────────────────────────────────────────────────────────────
220	
221	describe('Resident Integration — Inactive-occupancy warning', () => {
222	  let service: ResidentService;
223	  let property: PropertyService;
224	  let db: DbService;
225	
226	  beforeEach(async () => {
227	    ({ service, property, db } = await setup());
228	  });
229	  afterEach(async () => { await teardown(db); });
230	
231	  it('warns when setting status to inactive while resident has active occupancy', async () => {
232	    const r = await service.createResident({ ...BASE, email: 'warn@hp.local' }, 1, 'admin');
233	
234	    await db.occupancies.add({
235	      residentId:    r.id!,
236	      roomId:        1,
237	      effectiveFrom: new Date(),
238	      reasonCode:    'MOVE_IN_NEW',
239	      status:        'active',
240	      createdAt:     new Date(),
241	    });
242	
243	    const { warnings } = await service.updateResident(
244	      r.id!, { status: 'inactive' }, 1, 'admin',
245	    );
246	
247	    expect(warnings.length).toBeGreaterThan(0);
248	    expect(warnings[0].toLowerCase()).toContain('active room assignment');
249	  });
250	
251	  it('no warning when setting inactive for resident with no occupancy', async () => {
252	    const r = await service.createResident({ ...BASE, email: 'nowarn@hp.local' }, 1, 'admin');
253	
254	    const { warnings } = await service.updateResident(
255	      r.id!, { status: 'inactive' }, 1, 'admin',
256	    );
257	
258	    expect(warnings.length).toBe(0);
259	  });
260	});
261	
262	// ──────────────────────────────────────────────────────────────────────────────
263	// Change log
264	// ──────────────────────────────────────────────────────────────────────────────
265	
266	describe('Resident Integration — Change log', () => {
267	  let service: ResidentService;
268	  let db: DbService;
269	
270	  beforeEach(async () => {
271	    ({ service, db } = await setup());
272	  });
273	  afterEach(async () => { await teardown(db); });
274	
275	  it('getChangeLog returns entries for only the target resident', async () => {
276	    const r1 = await service.createResident({ ...BASE, email: 'cl1@hp.local' }, 1, 'admin');
277	    const r2 = await service.createResident({ ...BASE, email: 'cl2@hp.local' }, 1, 'admin');
278	
279	    await service.updateResident(r1.id!, { phone: '111-0001' }, 1, 'admin');
280	    await service.updateResident(r2.id!, { phone: '222-0002' }, 1, 'admin');
281	
282	    const log = await service.getChangeLog(r1.id!);
283	    for (const entry of log) {
284	      expect(Number(entry.targetId)).toBe(r1.id);
285	    }
286	  });
287	
288	  it('getChangeLog is sorted descending by timestamp', async () => {
289	    const r = await service.createResident({ ...BASE, email: 'sort@hp.local' }, 1, 'admin');
290	    await service.updateResident(r.id!, { phone: '555-1111' }, 1, 'admin');
291	    await service.updateResident(r.id!, { phone: '555-2222' }, 1, 'admin');
292	
293	    const log = await service.getChangeLog(r.id!);
294	    expect(log.length).toBeGreaterThanOrEqual(3);
295	    for (let i = 0; i < log.length - 1; i++) {
296	      expect(new Date(log[i].timestamp).getTime())
297	        .toBeGreaterThanOrEqual(new Date(log[i + 1].timestamp).getTime());
298	    }
299	  });
300	});
301	
302	// ──────────────────────────────────────────────────────────────────────────────
303	// searchResidents
304	// ──────────────────────────────────────────────────────────────────────────────
305	
306	describe('Resident Integration — searchResidents', () => {
307	  let service: ResidentService;
308	  let db: DbService;
309	
310	  beforeEach(async () => {
311	    ({ service, db } = await setup());
312	  });
313	  afterEach(async () => { await teardown(db); });
314	
315	  it('returns empty array for blank query', async () => {
316	    expect(await service.searchResidents('')).toEqual([]);
317	    expect(await service.searchResidents('  ')).toEqual([]);
318	  });
319	
320	  it('finds residents by email substring', async () => {
321	    await service.createResident({ ...BASE, email: 'findbyme@hp.local' }, 1, 'admin');
322	
323	    const results = await service.searchResidents('findbyme');
324	    expect(results.some(r => r.email === 'findbyme@hp.local')).toBe(true);
325	  });
326	
327	  it('finds residents by last name', async () => {
328	    await service.createResident(
329	      { ...BASE, lastName: 'Unique123', email: 'unique123@hp.local' }, 1, 'admin',
330	    );
331	
332	    const results = await service.searchResidents('Unique123');
333	    expect(results.some(r => r.lastName === 'Unique123')).toBe(true);
334	  });
335	});
